use Mix.Config

# For production, don't forget to configure the url host
# to something meaningful, Phoenix uses this information
# when generating URLs.
#
# Note we also include the path to a cache manifest
# containing the digested version of static files. This
# manifest is generated by the `mix phx.digest` task,
# which you should run after static files are built and
# before starting your production server.

config :ragged_web, RaggedWeb.Endpoint,
  url: [host: "localhost", port: 5060],
  cache_static_manifest: "priv/static/cache_manifest.json",
  check_origin: false,
  server: true,
  root: "."

config :logger, level: :info

config :ragged_web, RaggedWeb.Endpoint,
  http: [:inet6, port: String.to_integer(System.get_env("PORT") || "5060")],
  secret_key_base: "veryverysecretkeyeryverysecretkeyveryverysecretkeyveryverysecretkey"

config :ragged_data, RaggedData.Repo,
  username: "postgres",
  password: "postgres",
  database: "ragged_data_prod",
  hostname: "localhost",
  show_sensitive_data_on_connection_error: true,
  pool_size: 10

config :ragged_data, RaggedWeb.Influx,
  database: "ragged_app_prod",
  host: "localhost",
  http_opts: [insecure: true],
  pool: [max_overflow: 10, size: 50],
  port: 8086,
  port_udp: 8089,
  scheme: "http",
  auth: [method: :basic, username: "admin", password: "admin"],
  # writer: Instream.Writer.Line
  writer: Instream.Writer.UDP

